### 2) `ZSTD_adjustCParams_internal()` performs size/mode-specific reductions for `windowLog`, `hashLog`, and `chainLog`

```c
1411: static ZSTD_compressionParameters
1412: ZSTD_adjustCParams_internal(ZSTD_compressionParameters cPar,
1413:                             unsigned long long srcSize,
1414:                             size_t dictSize,
1415:                             ZSTD_cParamMode_e mode)
1416: {
1417:     const U64 minSrcSize = 513; /* (1<<9) + 1 */
1418:     const U64 maxWindowResize = 1ULL << (ZSTD_WINDOWLOG_MAX-1);
1419:     assert(ZSTD_checkCParams(cPar)==0);
1420: 
1421:     switch (mode) {
1422:     case ZSTD_cpm_unknown:
1423:     case ZSTD_cpm_noAttachDict:
1424:         /* If we don't know the source size, don't make any
1425:          * assumptions about it. We will already have selected
1426:          * smaller parameters if a dictionary is in use.
1427:          */
1428:         break;
1429:     case ZSTD_cpm_createCDict:
1430:         /* Assume a small source size when creating a dictionary
1431:          * with an unknown source size.
1432:          */
1433:         if (dictSize && srcSize == ZSTD_CONTENTSIZE_UNKNOWN)
1434:             srcSize = minSrcSize;
1435:         break;
1436:     case ZSTD_cpm_attachDict:
1437:         /* Dictionary has its own dedicated parameters which have
1438:          * already been selected. We are selecting parameters
1439:          * for only the source.
1440:          */
1441:         dictSize = 0;
1442:         break;
1443:     default:
1444:         assert(0);
1445:         break;
1446:     }
1447: 
1448:     /* resize windowLog if input is small enough, to use less memory */
1449:     if ( (srcSize <= maxWindowResize)
1450:       && (dictSize <= maxWindowResize) )  {
1451:         U32 const tSize = (U32)(srcSize + dictSize);
1452:         static U32 const hashSizeMin = 1 << ZSTD_HASHLOG_MIN;
1453:         U32 const srcLog = (tSize < hashSizeMin) ? ZSTD_HASHLOG_MIN :
1454:                             ZSTD_highbit32(tSize-1) + 1;
1455:         if (cPar.windowLog > srcLog) cPar.windowLog = srcLog;
1456:     }
1457:     if (srcSize != ZSTD_CONTENTSIZE_UNKNOWN) {
1458:         U32 const dictAndWindowLog = ZSTD_dictAndWindowLog(cPar.windowLog, (U64)srcSize, (U64)dictSize);
1459:         U32 const cycleLog = ZSTD_cycleLog(cPar.chainLog, cPar.strategy);
1460:         if (cPar.hashLog > dictAndWindowLog+1) cPar.hashLog = dictAndWindowLog+1;
1461:         if (cycleLog > dictAndWindowLog)
1462:             cPar.chainLog -= (cycleLog - dictAndWindowLog);
1463:     }
1464: 
1465:     if (cPar.windowLog < ZSTD_WINDOWLOG_ABSOLUTEMIN)
1466:         cPar.windowLog = ZSTD_WINDOWLOG_ABSOLUTEMIN;  /* minimum wlog required for valid frame header */
1467: 
1468:     if (mode == ZSTD_cpm_createCDict && ZSTD_CDictIndicesAreTagged(&cPar)) {
1469:         U32 const maxShortCacheHashLog = 32 - ZSTD_SHORT_CACHE_TAG_BITS;
1470:         if (cPar.hashLog > maxShortCacheHashLog) {
1471:             cPar.hashLog = maxShortCacheHashLog;
1472:         }
1473:     }
1474: 
1475:     return cPar;
1476: }
